    pub fn setScrollRegion(self: *Screen, top: u32, bottom: u32) void {
        const t = if (top > 0) top - 1 else 0;
        const b = if (bottom > 0) @min(bottom - 1, self.grid.rows -| 1) else self.grid.rows -| 1;
        if (t < b) {
