            self.rlower = b;
        }
    }

    /// Scroll the scroll region up by n lines.
    /// Shifts lines within [rupper..rlower] upward and clears the bottom.
    pub fn scrollUp(self: *Screen, n: u32) void {
        var i: u32 = 0;
        while (i < n) : (i += 1) {
            if (self.rupper == 0 and self.rlower == self.grid.rows -| 1) {
